import React from 'react'
import { Button, Navbar, Nav, NavDropdown, Form, FormControl } from 'react-bootstrap';
import 'bootstrap/dist/css/bootstrap.min.css';
import { BrowserRouter as Router, Swicth, Route, Switch, withRouter, NavLink, Link } from 'react-router-dom';
import { GitHub, HomeRounded, NavigateNextRounded, Telegram } from '@material-ui/icons';
import GitHubIcon from '@material-ui/icons/GitHub';

import useStyle from './styles.js';
import resumeData from '../../utils/resumeData.js';
import CustomButton from '../Button/Button.js';
import CustomButtonLink from '../ButtonLink/ButtonLink.js';

const Header = (props) => {
    const pathName = props?.location?.pathname;
    const classes = useStyle();
    return (
        <Navbar expand="lg" className={classes.header}>
            {/* Home Link */}
            <Nav.Link as={NavLink} to="/" className={classes.header_navlink}>
                <Navbar.Brand className={classes.header_home}>
                    <HomeRounded />
                </Navbar.Brand>
            </Nav.Link>

            <Navbar.Toggle />

            <Navbar.Collapse>
                <Nav className={classes.header_left}>
                    {/* Resume Link */}
                    <Nav.Link as={NavLink} to="/" className={pathName == "/" ? classes.header_link_active : classes.header_link}>Resume</Nav.Link>
                    {/* Portofolio Link */}
                    <Nav.Link as={NavLink} to="/portofolio" className={pathName == "/portofolio" ? classes.header_link_active : classes.header_link}>Portofolio</Nav.Link>
                    {/* Contact Link */}
                    <Nav.Link as={NavLink} to="/contact" className={pathName == "/contact" ? classes.header_link_active : classes.header_link}>Contact</Nav.Link>
                </Nav>

                <div className={classes.header_right}>
                    {Object.keys(resumeData.socials).map((key) => (
                        <a href={resumeData.socials[key].link} target="_blank">{resumeData.socials[key].icon}</a>
                    ))}
                    <CustomButtonLink text="Hire Me" icon={<Telegram />} link={resumeData.wa} />
                </div>
            </Navbar.Collapse>
        </Navbar>
    )
}

export default withRouter(Header);
