import { CardMedia, Typography } from '@material-ui/core'
import React from 'react'

import useStyle from './styles.js';
import imageProfile from '../../assets/images/displayImage.jpg';
import CustomTimeLine, { CustomTimeLineSeparator } from '../Timeline/Timeline.js';
import resumeData from '../../utils/resumeData';
import { PersonOutlineOutlined, GetApp } from '@material-ui/icons';
import TimelineItem from '@material-ui/lab/TimelineItem';
import TimelineContent from '@material-ui/lab/TimelineContent';
import CustomButtonLink from '../ButtonLink/ButtonLink';
import CV from '../../assets/images/cv.pdf';

const CustomTimeLineItem = ({title, text, link}) => {
    const classes = useStyle();
    return(
    <TimelineItem>
        <CustomTimeLineSeparator />
        <TimelineContent className={classes.content}>            
            {link ? (
                <Typography className={classes.allText}>
                    <b className={classes.text}>{title}:</b>{" "}
                    <a href={link} target='_blank' className={classes.link}>
                        {text}
                    </a>
                </Typography>
            ) : (
                <Typography className={classes.allText}><b className={classes.text}>{title}:</b> {text}</Typography>
            )}
        </TimelineContent>
    </TimelineItem>
)}

const Profile = () => {
    const classes = useStyle();
    return (
        <div className={classes.profile, "container_shadow"}>
            <div className={classes.profileName}>
                <Typography className={classes.name}>{resumeData.name}</Typography>
                <Typography className={classes.title}>{resumeData.title}</Typography>
            </div>

            <figure className={classes.profileImage}>                
                <img className={classes.img} src={imageProfile} alt="" />                
            </figure>

            <div className={classes.profileInformation}>
                <CustomTimeLine icon={<PersonOutlineOutlined />} >
                    <CustomTimeLineItem title="Name" text={resumeData.name} />
                    <CustomTimeLineItem title="Title" text={resumeData.title} />
                    <CustomTimeLineItem title="Email" text={resumeData.email} />
                    <CustomTimeLineItem title="Phone" text={resumeData.phone} />

                    {Object.keys(resumeData.socials).map((key) => (
                        <CustomTimeLineItem title={key} text={resumeData.socials[key].text} link={resumeData.socials[key].link}/>
                    ))}
                </CustomTimeLine>
                
                <div className={classes.button_container}>
                    <CustomButtonLink text="Download CV" icon={<GetApp />} link={CV}  />
                </div>
            </div>
        </div>
    )
}

export default Profile
