import { Card, CardActionArea, CardContent, CardMedia, Dialog, DialogActions, DialogContent, DialogTitle, Grid, Grow, Tab, Tabs, Typography } from '@material-ui/core';
import React, { useState } from 'react';

import ImageGallery from '../../components/ImageGallery/ImageGallery.js';
import resumeData from '../../utils/resumeData.js';
import useStyle from './styles.js';

const Portofolio = () => {
    const classes = useStyle();
    const [tabValue, setTabValue] = useState('All');
    const [projectDialog, setProjectDialog] = useState(false);

    const ProjectDialog = () => (
        <Dialog open={projectDialog} onClose={() => setProjectDialog(false)} className={classes.projectDialog} maxWidth={"lg"}
            >
            <DialogTitle onClose={() => setProjectDialog(false)} >
                {projectDialog.title}
            </DialogTitle>
            <DialogContent style={{height: '80vh'}}>

                {projectDialog.image && (
                    <ImageGallery images={projectDialog.image} />
                )}

                <Typography className={classes.projectDialog_description}>{projectDialog.description}</Typography>                    
            </DialogContent>
            <DialogActions className={classes.projectDialog_actions}>
                {projectDialog?.links?.map(link => (
                    <a href={link.link} target='_blank' className={classes.projectDialog_icon}>
                        {link.icon}
                    </a>
                ))}
            </DialogActions>
        </Dialog>
    );

    const CardProject = (project) => (
        <Grid item xs={12} sm={6} md={6} lg={4} >
            <Grow in timeout={1000}>                                
                <Card className={classes.customCard} onClick={() => setProjectDialog(project)}>
                    <CardActionArea>
                        <CardMedia className={classes.customCard_image} image={project.image[0]} title={project.title} />
                        <CardContent>
                            <Typography className={classes.customCard_title}>{project.title}</Typography>
                            <Typography variant="body2" className={classes.customCard_description}>{project.description}</Typography>
                        </CardContent>
                    </CardActionArea>
                </Card>                                
            </Grow>
        </Grid>
    );

    return (
        <Grid spacing={1} container className="section pt_20 pb_45">
            {/* Title */}
            <Grid item className="section_title mb_30" >
                <h6>Portofolio</h6>
            </Grid>

            {/* Tabs */}
            <Grid item xs={12}>
                <Tabs 
                    value={tabValue} 
                    indicatorColor="white" 
                    className={classes.customTabs} 
                    onChange={(event, newValue) => { setTabValue(newValue); }}
                >
                    <Tab 
                        label="All" 
                        value="All" 
                        className={tabValue == 'All' ? classes.active : classes.customTabs_item}                             
                    />
                    {[...new Set(resumeData.tagsProject.map(tag => tag))].map(
                        tag => (
                            <Tab 
                                label={tag} 
                                value={tag} 
                                className={tabValue == tag ? classes.active : classes.customTabs_item}                     
                            />
                        )
                    )}
                </Tabs>
            </Grid>

            {/* Projects */}
            <Grid item xs={12}>
                <Grid container spacing={3} className="">                
                    {resumeData.projects.map(project => (
                        <>
                        {tabValue != "All" ? project.tags.map(tag => {
                            if (tabValue == tag) {
                                return CardProject(project);                           
                            } else {
                                return null;
                            }
                        }) : CardProject(project) }
                        </>                            
                    ))}
                </Grid>
            </Grid>
                        
            {/* Project Dialog */}
            {ProjectDialog()}
            
        </Grid>
    )
}

export default Portofolio
