import { makeStyles } from '@material-ui/core/styles';

export default makeStyles({
    profile: {
        backgroundColor: 'black',
    },
    profileName: {
        lineHeight: '18px',
        padding: '20px',
    },
    name: {
        textTransform: 'uppercase',
        fontSize: '17px',
        fontWeight: 'bold'
    },
    title: {
        fontSize: '17px',
        color: '#777'
    },
    profileImage: {
        marginTop: -'10px',
        WebkitClipPath: "polygon(0 9%, 100% 0, 100% 94%, 0 100%)",        
        clipPath: "polygon(0 9%, 100% 0, 100% 94%, 0 100%)",
    },
    img: {
        width: '100%',
    },
    // Information
    profileInformation: {
        top: '0',
        left: '0',
        margin: '-30px 10px 30px',
        paddingBottom: '20px',
    },
    content: {
        marginTop: '2px',
        marginBottom: '2px',        
        fontSize: '13.5px !important',
    },
    allText: {       
        fontSize: '13.5px !important',
        color: '#787878',
        display: 'inline-block',
    },
    text: {
        fontWeight: '400 !important',  
        color: 'black'      ,
    },
    link: {
        textDecoration: 'none',
        color: '#787878',
    },
    button_container: {
        width: '100%',
        display: 'flex !important',
        justifyContent: 'center',
        marginTop: '30px',
    }
})