import { Grid, Icon, Paper, TextField, Typography } from '@material-ui/core';
import React from 'react';
import resumeData from '../../utils/resumeData';
import useStyle from './styles';
import CustomTimeLine, { CustomTimeLineSeparator } from '../../components/Timeline/Timeline.js';
import WorkIcon from '@material-ui/icons/Work';
import SchoolIcon from '@material-ui/icons/School';
import TimelineItem from '@material-ui/lab/TimelineItem';
import TimelineDot from '@material-ui/lab/TimelineDot';
import TimelineConnector from '@material-ui/lab/TimelineConnector';
import TimelineSeparator from '@material-ui/lab/TimelineSeparator';
import TimelineContent from '@material-ui/lab/TimelineContent';
import CustomButton from '../../components/Button/Button';

const Resume = () => {
    const classes = useStyle();

    return (
        <>
            {/* About Me */}
            <Grid container className="section pt_20 pb_45">
                <Grid item className="section_title mb_20" >
                    <h6>About Me</h6>
                </Grid>
                <Grid item xs={12}>
                    <Typography variant="body2" className={classes.aboutme_text}>{resumeData.about}</Typography>
                </Grid>
            </Grid>

            {/* Experiences & Education */}
            <Grid container className="section pb_45">
                <Grid item className="section_title mb_30" >
                    <h6>Resume</h6>
                </Grid>

                <Grid item xs={12}>
                    <Grid container className={classes.resume_timeline}>
                        {/* Experiene */}
                        <Grid item sm={12} md={6}>
                            <CustomTimeLine title="Working Experience" icon={<WorkIcon />}>
                                {resumeData.experiences.map(experience => (
                                    <TimelineItem>       
                                    <CustomTimeLineSeparator />               
                                        <TimelineContent>
                                            <Typography className={classes.timeline_title}>{experience.title}</Typography>
                                            <Typography variant="caption" className={classes.timeline_date}>{experience.date}</Typography>
                                            <Typography variant="body2" className={classes.timeline_description}>{experience.description}</Typography>
                                        </TimelineContent>
                                    </TimelineItem>
                                ))}
                            </CustomTimeLine>
                        </Grid>
                        {/* Education */}
                        <Grid item sm={12} md={6}>
                            <CustomTimeLine title="Education" icon={<SchoolIcon />}>
                                {resumeData.educations.map(education => (
                                    <TimelineItem>       
                                    <CustomTimeLineSeparator />               
                                        <TimelineContent>
                                            <Typography className={classes.timeline_title}>{education.title}</Typography>
                                            <Typography variant="caption" className={classes.timeline_date}>{education.date}</Typography>
                                            <Typography variant="body2" className={classes.timeline_description}>{education.description}</Typography>
                                        </TimelineContent>
                                    </TimelineItem>
                                ))}
                            </CustomTimeLine>
                        </Grid>
                    </Grid>
                </Grid>
            </Grid>

            {/* Services */}
            <Grid container className="section pb_45">
                <Grid item className="section_title mb_30" >
                    <h6>My Services</h6>
                </Grid>

                <Grid item xs={12}>
                    <Grid container spacing={3} justify="space-around" >
                        {resumeData.services.map(service => (
                            <Grid item xs={12} sm={6} md={3} >
                                <div className={classes.service}>
                                    <Icon className={classes.service_icon}>{service.icon}</Icon>
                                    <Typography className={classes.service_title} variant="h6">{service.title}</Typography>
                                    <Typography className={classes.service_description} variant="body2">{service.description}</Typography>
                                </div>
                            </Grid>
                        ))}
                    </Grid>
                </Grid>
            </Grid>

            {/* Skill */}
            <Grid container className="section graygb pb_45 p_50">
                <Grid item xs={12}>
                    <Grid container spacing={3} justify="space-between">
                        {resumeData.skills.map(skill => (
                            <Grid item xs={12} sm={6} md={3}>
                                <Paper elevation={0} className={classes.skill}>
                                    <Typography variant="h6" className={classes.skill_title}>
                                        {skill.title}
                                    </Typography>
                                    {skill.description.map(element => (
                                        <Typography variant={'outlined'} className={classes.skill_description}>
                                            <TimelineDot className={classes.timeline_dot}/> 
                                            {element}
                                        </Typography>
                                    ))}
                                </Paper>
                            </Grid>
                        ))}
                    </Grid>
                </Grid>
            </Grid>

        </>
    )
}

export default Resume;
