import { Grid, Icon, Paper, TextField, Typography } from '@material-ui/core';
import React from 'react';
import resumeData from '../../utils/resumeData';
import useStyle from './styles';
import CustomButton from '../../components/Button/Button';

function Contact() {
    const classes = useStyle();
    return (
        <>
            {/* Contact */}
            <Grid container className="section pt_45 pb_45" spacing={5}>
                {/* Form */}
                <Grid item xs={12} lg={7} >
                    <Grid container>
                        <Grid item className="section_title mb_30" >
                            <h6>Contact Form</h6>
                        </Grid>
                    </Grid>

                    <Grid item xs={12}>
                        <Grid container spacing={2}>
                            <Grid item xs={12} sm={6}>
                                <TextField fullWidth name="name" label="Name" />
                            </Grid>
                            <Grid item xs={12} sm={6}>
                                <TextField fullWidth name="email" label="E-Mail" />
                            </Grid>
                            <Grid item xs={12}>
                                <TextField fullWidth name="message" label="Message" multiline rows={4} />
                            </Grid>
                            <Grid item xs={12}>
                                <CustomButton text="Submit" />
                            </Grid>
                        </Grid>
                    </Grid>
                </Grid>

                {/* Information */}
                <Grid item xs={12} lg={5} >
                    <Grid container>
                        <Grid item className="section_title mb_30" >
                            <h6>Contact Informations</h6>
                        </Grid>
                    </Grid>

                    <Grid item xs={12}>
                        <Grid container spacing={2}>
                            <Grid item xs={12}>
                                <Typography className={classes.contactInfo_item}>
                                    <span>Address: </span>{resumeData.address}
                                </Typography>
                            </Grid>
                            <Grid item xs={12}>
                                <Typography className={classes.contactInfo_item}>
                                    <span>Phone: </span>{resumeData.phone}
                                </Typography>
                            </Grid>
                            <Grid item xs={12}>
                                <Typography className={classes.contactInfo_item}>
                                    <span>E-Mail: </span>{resumeData.email}
                                </Typography>
                            </Grid>
                        </Grid>
                    </Grid>
                    
                    <Grid item xs={12}>
                        <Grid container className={classes.contactInfo_socialContainer}>
                            {Object.keys(resumeData.socials).map(key => (
                                <Grid item className={classes.contactInfo_social} >
                                    <a href={resumeData.socials[key].link}>{resumeData.socials[key].icon}</a>
                                </Grid>
                            ))}
                        </Grid>
                    </Grid>
                </Grid>
            </Grid>
        </>
    )
}

export default Contact
