import { makeStyles } from '@material-ui/core/styles';

export default makeStyles({    
    aboutme_text: {
        color: 'darklategray',
        font: 'smaller',
        lineHeight: '22px',
        whiteSpace: 'pre-line'
    },
    timeline_title: {
        fontSize: '16px',
        fontWeight: '500'
    },
    timeline_date: {
        color: 'darklategray',
    },
    timeline_description: {
        color: 'gray',
        fontSize: 'small',
        marginTop: '6px',
    },

    // services
    service: {
        height: '100%',
        textAlign: 'center',
    },
    service_icon: {
        '& > .MuiSvgIcon-root': {
            fontSize: '46px',
            marginLeft: '0',
            fontWeight: '300',
            color: 'darklategray'
        }
    },
    service_title: {
        fontSize: '16px',
        fontWeight: '500',
        lineHeight: '35px',
        textAlign: 'center'
    },
    service_description: {
        color: '#989898 !important',
        borderColor: 'var(--main-color)',
        marginRight: '5px',
        textAlign: 'center'
    },
    // Skill
    skill: {
        borderRadius: '8px !important',
        padding: '20px !important',
        boxShadow: '0 0 48px 0 rgba(4, 6, 4, 0.08) !important',
        minHeight: '186px !important',
        height: '100% !important',
    },
    skill_title: {
        fontSize: '14px !important',
        fontWeight: '500 !important',
        lineHeight: '35px !important',
    },
    skill_description: {
        display: 'flex',
        alignItems: 'center',
        color: '#989898',
        fontWeight: '400',
        lineHeight: '18px',
    },
    timeline_dot: {
        borderColor: 'var(--main-color) !important',
        backgroundColor: 'white',
        padding: '2px !important',
        marginRight: '5px !important',
    },

    // Contacts
    contactInfo_item: {
        fontSize: '14px',
        color: '#787878',
        '& > span ': {
            color: 'black',
            fontWeight: '500',
        },

    },
    contactInfo_social: {
        '& > a > .MuiSvgIcon-root': {
            fontSize: '16px !important',
            marginRight: '10px',
            color: 'black',
        }
    },
    contactInfo_socialContainer: {
        marginTop: '25px',
        
    },

});


